<?php use App\Helpers\Authorization; ?>
<div class="mb-4"><h1 class="h3 mb-1">Roles y permisos</h1><p class="text-secondary mb-0">Controle las funciones disponibles para cada perfil.</p></div>
<div class="row g-3"><?php foreach ($roles as $role): ?><div class="col-md-6 col-xl-4"><div class="card h-100 shadow-sm"><div class="card-body"><div class="d-flex justify-content-between"><h2 class="h5"><?= htmlspecialchars($role['Nombre'], ENT_QUOTES, 'UTF-8') ?></h2><span class="badge text-bg-<?= (int)$role['Estado'] ? 'success' : 'secondary' ?>"><?= (int)$role['Estado'] ? 'Activo' : 'Inactivo' ?></span></div><p class="text-secondary"><?= htmlspecialchars($role['Descripcion'] ?? '', ENT_QUOTES, 'UTF-8') ?></p><div class="small mb-3"><strong><?= (int)$role['Usuarios'] ?></strong> usuarios · <strong><?= (int)$role['Permisos'] ?></strong> permisos</div><?php if (Authorization::can('roles.editar')): ?><a class="btn btn-outline-primary btn-sm" href="index.php?route=roles/permisos&id=<?= (int)$role['IdRol'] ?>">Configurar permisos</a><?php endif; ?></div></div></div><?php endforeach; ?></div>
